  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// Admin users\nmodel Admin {\n  id           BigInt   @id @default(autoincrement())\n  email        String   @unique @db.Citext\n  passwordHash String   @map(\"password_hash\")\n  fullName     String   @map(\"full_name\")\n  createdAt    DateTime @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n\n  // Relations\n  reviewedApprovals DoctorApproval[]\n\n  @@map(\"admins\")\n}\n\n// Patient users\nmodel User {\n  id           BigInt   @id @default(autoincrement())\n  email        String   @unique @db.Citext\n  passwordHash String   @map(\"password_hash\")\n  fullName     String   @map(\"full_name\")\n  phone        String\n  dob          DateTime @db.Date\n  sex          Sex\n  address      String?\n  createdAt    DateTime @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n\n  // Relations\n  tokens    Token[]\n  tokenLogs TokenLog[]\n\n  @@map(\"users\")\n}\n\n// Doctor users\nmodel Doctor {\n  id                  BigInt   @id @default(autoincrement())\n  email               String   @unique @db.Citext\n  passwordHash        String   @map(\"password_hash\")\n  fullName            String   @map(\"full_name\")\n  phone               String\n  dob                 DateTime @db.Date\n  sex                 Sex\n  qualification       String\n  specialization      String\n  yearsExperience     Int      @map(\"years_experience\")\n  licenseNumber       String   @map(\"license_number\")\n  licenseDocumentPath String?  @map(\"license_document_path\")\n  isActive            Boolean  @default(false) @map(\"is_active\")\n  createdAt           DateTime @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n\n  // Relations\n  approvals DoctorApproval[]\n  sessions  Session[]\n  tokenLogs TokenLog[]\n\n  @@map(\"doctors\")\n}\n\n// Doctor approval system\nmodel DoctorApproval {\n  id         BigInt         @id @default(autoincrement())\n  doctorId   BigInt         @map(\"doctor_id\")\n  status     ApprovalStatus\n  reviewedBy BigInt?        @map(\"reviewed_by\")\n  reviewedAt DateTime?      @map(\"reviewed_at\") @db.Timestamptz(6)\n  note       String?\n  createdAt  DateTime       @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n\n  // Relations\n  doctor   Doctor @relation(fields: [doctorId], references: [id], onDelete: Cascade)\n  reviewer Admin? @relation(fields: [reviewedBy], references: [id])\n\n  @@index([doctorId], map: \"doctor_approvals_doctor_idx\")\n  @@map(\"doctor_approvals\")\n}\n\n// Doctor sessions (one per day per doctor)\nmodel Session {\n  id             BigInt        @id @default(autoincrement())\n  doctorId       BigInt        @map(\"doctor_id\")\n  sessionDate    DateTime      @map(\"session_date\") @db.Date\n  status         SessionStatus @default(NOT_STARTED)\n  currentTokenNo Int           @default(0) @map(\"current_token_no\")\n  maxTokenNo     Int           @default(0) @map(\"max_token_no\")\n  startedAt      DateTime?     @map(\"started_at\") @db.Timestamptz(6)\n  endedAt        DateTime?     @map(\"ended_at\") @db.Timestamptz(6)\n\n  // Relations\n  doctor    Doctor     @relation(fields: [doctorId], references: [id], onDelete: Cascade)\n  tokens    Token[]\n  tokenLogs TokenLog[]\n\n  @@unique([doctorId, sessionDate])\n  @@index([doctorId, status], map: \"sessions_doctor_active_idx\")\n  @@map(\"sessions\")\n}\n\n// Individual tokens\nmodel Token {\n  id         BigInt      @id @default(autoincrement())\n  sessionId  BigInt      @map(\"session_id\")\n  patientId  BigInt      @map(\"patient_id\")\n  tokenNo    Int         @map(\"token_no\")\n  status     TokenStatus @default(WAITING)\n  bookedAt   DateTime    @default(now()) @map(\"booked_at\") @db.Timestamptz(6)\n  calledAt   DateTime?   @map(\"called_at\") @db.Timestamptz(6)\n  servedAt   DateTime?   @map(\"served_at\") @db.Timestamptz(6)\n  canceledAt DateTime?   @map(\"canceled_at\") @db.Timestamptz(6)\n  noShowAt   DateTime?   @map(\"no_show_at\") @db.Timestamptz(6)\n\n  // Relations\n  session   Session    @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  patient   User       @relation(fields: [patientId], references: [id], onDelete: Cascade)\n  tokenLogs TokenLog[]\n\n  @@unique([sessionId, tokenNo])\n  @@index([sessionId, status, tokenNo], map: \"tokens_session_status_idx\")\n  @@index([patientId, sessionId], map: \"tokens_patient_session_idx\")\n  @@map(\"tokens\")\n}\n\n// Audit log for all token and session actions\nmodel TokenLog {\n  id        BigInt    @id @default(autoincrement())\n  tokenId   BigInt?   @map(\"token_id\")\n  sessionId BigInt?   @map(\"session_id\")\n  doctorId  BigInt?   @map(\"doctor_id\")\n  patientId BigInt?   @map(\"patient_id\")\n  action    LogAction\n  meta      Json?     @db.JsonB\n  createdAt DateTime  @default(now()) @map(\"created_at\") @db.Timestamptz(6)\n\n  // Relations\n  token   Token?   @relation(fields: [tokenId], references: [id], onDelete: Cascade)\n  session Session? @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  doctor  Doctor?  @relation(fields: [doctorId], references: [id], onDelete: Cascade)\n  patient User?    @relation(fields: [patientId], references: [id], onDelete: Cascade)\n\n  @@index([action, createdAt], map: \"token_logs_action_time_idx\")\n  @@map(\"token_logs\")\n}\n\n// Enums\nenum Sex {\n  M\n  F\n  O\n}\n\nenum ApprovalStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nenum SessionStatus {\n  NOT_STARTED\n  ACTIVE\n  PAUSED\n  ENDED\n}\n\nenum TokenStatus {\n  WAITING\n  CALLED\n  SERVED\n  CANCELED\n  NO_SHOW\n}\n\nenum LogAction {\n  BOOKED\n  CALLED\n  SERVED\n  CANCELED\n  NO_SHOW\n  SESSION_START\n  SESSION_PAUSE\n  SESSION_RESUME\n  SESSION_END\n}\n",
